+    /// Fast path for `SELECT COUNT(*) FROM table WHERE col IN (literal_list)`.
+    ///
+    /// After IN-subquery rewriting, the IN set is a flat literal list.
+    /// Instead of compiling and interpreting VDBE bytecode for the full
+    /// 100K-row scan, build a `HashSet` of the IN values and count
+    /// matching rows directly against MemDB.
+    fn try_direct_count_star_in_list(&self, select: &SelectStatement) -> Result<Option<Vec<Row>>> {
+        if select.with.is_some()
+            || !select.order_by.is_empty()
+            || select.limit.is_some()
+            || !select.body.compounds.is_empty()
+        {
+            return Ok(None);
+        }
+        let SelectCore::Select {
+            distinct,
+            columns,
+            from: Some(from),
+            where_clause: Some(where_expr),
+            group_by,
+            having,
+            windows,
+            ..
+        } = &select.body.select
+        else {
+            return Ok(None);
+        };
+        if *distinct != Distinctness::All
+            || !group_by.is_empty()
+            || having.is_some()
+            || !windows.is_empty()
+            || !from.joins.is_empty()
+        {
+            return Ok(None);
+        }
+        let [ResultColumn::Expr { expr, .. }] = columns.as_slice() else {
+            return Ok(None);
+        };
+        let Expr::FunctionCall {
+            name,
+            args: FunctionArgs::Star,
+            distinct: false,
+            ..
+        } = expr
+        else {
+            return Ok(None);
+        };
+        if !name.eq_ignore_ascii_case("count") {
+            return Ok(None);
+        }
+        let TableOrSubquery::Table {
+            name: table_name,
+            index_hint: None,
+            time_travel: None,
+            ..
+        } = &from.source
+        else {
+            return Ok(None);
+        };
+        if table_name.schema.is_some() {
+            return Ok(None);
+        }
+        let where_expr: &Expr = where_expr.as_ref();
+        let Expr::In {
+            expr: in_col_expr,
+            set: InSet::List(literals),
+            not: false,
+            ..
+        } = where_expr
+        else {
+            return Ok(None);
+        };
+        let Expr::Column(col_ref, _) = in_col_expr.as_ref() else {
+            return Ok(None);
+        };
+        let (root_page, col_idx, rowid_alias_column_index) = {
+            let schema = self.schema.borrow();
+            let table = schema
+                .iter()
+                .find(|t| t.name.eq_ignore_ascii_case(&table_name.name));
+            let Some(table) = table else {
+                return Ok(None);
+            };
+            let col_idx = table
+                .columns
+                .iter()
+                .position(|c| c.name.eq_ignore_ascii_case(&col_ref.column));
+            let Some(col_idx) = col_idx else {
+                return Ok(None);
+            };
+            let rowid_alias = self
+                .rowid_alias_columns
+                .borrow()
+                .get(&table.name.to_ascii_lowercase())
+                .copied();
+            (table.root_page, col_idx, rowid_alias)
+        };
+        let mut set: std::collections::HashSet<SqliteValueHashable> =
+            std::collections::HashSet::with_capacity(literals.len());
+        for lit in literals {
+            let Expr::Literal(literal, _) = lit else {
+                return Ok(None);
+            };
+            let sv = match literal {
+                Literal::Null => continue,
+                Literal::Integer(v) => SqliteValue::Integer(*v),
+                Literal::Float(v) => SqliteValue::Float(*v),
+                Literal::String(v) => SqliteValue::Text(v.clone().into()),
+                Literal::Blob(v) => SqliteValue::Blob(v.clone().into()),
+                Literal::True => SqliteValue::Integer(1),
+                Literal::False => SqliteValue::Integer(0),
+                _ => return Ok(None),
+            };
+            set.insert(SqliteValueHashable(sv));
+        }
+        if set.is_empty() {
+            return Ok(Some(vec![Row {
+                values: vec![SqliteValue::Integer(0)],
+            }]));
+        }
+        let db = self.db.borrow();
+        let Some(table_data) = db.get_table(root_page) else {
+            return Ok(None);
+        };
+        let count = i64::try_from(
+            table_data
+                .iter_rows()
+                .filter(|(rowid, row_values)| {
+                    let val = memdb_row_value_with_rowid_alias(
+                        *rowid,
+                        row_values,
+                        col_idx,
+                        rowid_alias_column_index,
+                    );
+                    set.contains(&SqliteValueHashable(val))
+                })
+                .count(),
+        )
+        .map_err(|_| {
+            FrankenError::Internal(format!(
+                "COUNT(*) IN list exceeds i64 for root page {root_page}"
+            ))
+        })?;
+        Ok(Some(vec![Row {
+            values: vec![SqliteValue::Integer(count)],
+        }]))
+    }
