+fn resolve_operand_collation(expr: &Expr, schemas: &[TableSchema]) -> Option<String> {
+    if let Expr::Collate { collation, .. } = expr {
+        return Some(collation.clone());
+    }
+    if let Expr::Column(cr, _) = expr {
+        for schema in schemas {
+            let name_matches = cr
+                .table
+                .as_ref()
+                .is_none_or(|t| t.eq_ignore_ascii_case(&schema.name));
+            if name_matches {
+                if let Some(coll) = schema
+                    .columns
+                    .iter()
+                    .find(|c| c.name.eq_ignore_ascii_case(&cr.column))
+                    .and_then(|c| c.collation.clone())
+                {
+                    return Some(coll);
+                }
+            }
+        }
+    }
+    None
+}
